    msg.payload = payload.id;
    return [msg, null, null, null];
}

if (payload.ui_action === "edit") {
    delete payload.ui_action;
    msg.payload = payload;
    return [null, msg, null, null];
}

if (payload.ui_action === "manual") {
    msg.topic = "manual_feedback";
    msg.payload = { id: payload.id, action: payload.action, valve_pin: payload.valve_pin, duration_minutes: payload.duration_minutes };
    return [null, null, msg, null];
}

